/**
 * Loads .env into process.env, if present, before anything else runs.
 *
 * MUST be the FIRST import in server.ts (not just textually first — ES
 * modules evaluate ALL static imports, in declaration order, before the
 * importing file's own top-level code runs). The platform client module
 * reads its required env vars at its own module top level, so if this file
 * were imported after it (or .env were loaded inline in server.ts instead of
 * via a dedicated first import), that check would run against an empty
 * environment even when a real .env file exists on disk. (Found live as a
 * real bug in the first WooCommerce scaffold — fixed once, here, for every
 * platform.)
 */

if (typeof process.loadEnvFile === "function") {
  try {
    process.loadEnvFile();
  } catch (e) {
    if ((e as { code?: string }).code !== "ENOENT") throw e;
  }
}

src/mcpTools.ts:
/**
 * Adeptra Merchant — shared UCP catalog + cart tool implementation.
 * Generated identically for every platform provider — see shared.ts's
 * mcpToolsTs() header comment (in the Adeptra Merchant codebase that
 * generated this file) for the full design rationale. Only server.ts
 * varies per platform (which primitive functions it wires in here).
 *
 * DELIBERATELY DOES NOT IMPLEMENT CHECKOUT: no create_checkout/
 * get_checkout/update_checkout/complete_checkout/cancel_checkout tool
 * exists in this file. Payment stays with the merchant — see README.md's
 * "About UCP protocol conformance" section.
 */

import { z } from "zod";
import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";

// ---------------------------------------------------------------------------
// Types every provider's primitives satisfy (see each provider's server.ts
// for how its own client module's functions get wired in as these).
// ---------------------------------------------------------------------------

export interface NormalizedProduct {
  id: string;
  title: string;
  price?: string;
  currency?: string;
  url?: string;
}

export interface NormalizedLine {
  /** This line's own id (provider-assigned) — NOT the product id. */
  id: string;
  productId: string;
  quantity: number;
  title?: string;
  price?: string;
}

export interface NormalizedCart {
  lines: NormalizedLine[];
  currency?: string;
}

export interface CatalogPrimitives {
  searchProducts(query: string, limit: number): Promise<NormalizedProduct[]>;
  getProduct(id: string): Promise<NormalizedProduct>;
}

export interface CartPrimitives {
  getCartRaw(): Promise<NormalizedCart>;
  addItem(productId: string, quantity: number): Promise<unknown>;
  setItemQty(lineItemId: string, quantity: number): Promise<unknown>;
  removeItem(lineItemId: string): Promise<unknown>;
  /** Removes every line from the REAL platform cart. Used to guarantee a
   *  truly empty starting cart on create_cart (the platform cart may hold
   *  stale contents from before this session ever ran) and to make
   *  cancel_cart's platform-side emptying real, not just a session-state
   *  flag flip. */
  emptyCart(): Promise<unknown>;
  /** Mints a URL where the shopper completes payment on the merchant's own
   *  checkout, for the CURRENT platform cart. May be expensive / have real
   *  side effects (e.g. Wix creates an actual checkout object) — this file
   *  calls it lazily and caches the result; see resolveContinueUrl below. */
  checkoutUrl(): Promise<string>;
}

// ---------------------------------------------------------------------------
// meta["ucp-agent"] — REQUIRED on every request per UCP's MCP binding
// ("The meta['ucp-agent'] field is required on all requests" — both
// cart-mcp.md and catalog/mcp.md). Required here too, not optional; this
// server accepts and passes through whatever the calling agent sends but
// does not implement full capability-negotiation semantics against it
// (v1 scope — disclosed in README.md).
// ---------------------------------------------------------------------------

const metaSchema = z
  .object({
    "ucp-agent": z.object({ profile: z.string() }).passthrough(),
  })
  .passthrough();

// A submitted line item — quantity has minimum:1 per UCP's own
// line_item.json schema (zero is out of range, not a removal sentinel).
const lineItemInputSchema = z.object({
  id: z.string().optional(),
  item: z.object({ id: z.string() }),
  quantity: z.number().int().min(1),
});

const cartPayloadSchema = z.object({
  line_items: z.array(lineItemInputSchema),
  context: z.record(z.string(), z.unknown()).optional(),
});

// ---------------------------------------------------------------------------
// Business-outcome envelope helpers. UCP's wire shape returns a JSON-RPC
// SUCCESS (never a thrown/protocol error) for business outcomes like
// not_found — the MCP SDK's CallToolResult carries both a text-serialized
// content block (for plain-text MCP clients) and a structuredContent object
// matching UCP's literal result.structuredContent shape.
// ---------------------------------------------------------------------------

function toolResult(structuredContent: Record<string, unknown>) {
  return {
    content: [{ type: "text" as const, text: JSON.stringify(structuredContent, null, 2) }],
    structuredContent,
  };
}

function notFoundResult() {
  return toolResult({
    ucp: { status: "error" },
    messages: [{ type: "error", code: "not_found", content: "Cart not found or has expired", severity: "unrecoverable" }],
  });
}

function errorResult(code: string, message: string) {
  return toolResult({
    ucp: { status: "error" },
    messages: [{ type: "error", code, content: message, severity: "unrecoverable" }],
  });
}

function toUcpLineItems(lines: NormalizedLine[]) {
  return lines.map((l) => ({
    id: l.id,
    item: { id: l.productId, ...(l.title ? { title: l.title } : {}), ...(l.price ? { price: l.price } : {}) },
    quantity: l.quantity,
  }));
}

// ---------------------------------------------------------------------------
// Session state machine — ONE platform cart, ever. active/canceled.
// Module-level state: matches the same "one process = one shopper session"
// assumption every provider's own client module already makes (WooCommerce
// Cart-Token, Wix visitor token, Custom's single adapter instance) — this
// class formalizes it into the explicit state machine UCP's session model
// requires, instead of relying on the platform's own implicit single-cart
// behavior.
// ---------------------------------------------------------------------------

interface DesiredLine {
  id?: string;
  productId: string;
  quantity: number;
}

type CreateResult = { ok: true; id: string; cart: NormalizedCart } | { ok: false; error: string };
type GetResult = { ok: true; id: string; cart: NormalizedCart } | { ok: false; notFound: true };
type UpdateResult = { ok: true; cart: NormalizedCart } | { ok: false; notFound: true } | { ok: false; invalidLineId: string };
type CancelResult = { ok: true; cart: NormalizedCart } | { ok: false; notFound: true };

class CartSession {
  private state: "active" | "canceled" = "canceled"; // no cart yet behaves like canceled
  private cartId: string | null = null;
  private cachedContinueUrl: string | null = null;
  private continueUrlDirty = true;

  constructor(private primitives: CartPrimitives) {}

  private mintCartId(): string {
    return "cart_" + Date.now().toString(36) + Math.random().toString(36).slice(2, 8);
  }

  private matches(id: string): boolean {
    return this.state === "active" && this.cartId === id;
  }

  /** create_cart while a cart is ACTIVE is an error — never silently reset
   *  or return the existing cart. Destroying a basket must go through an
   *  explicit cancel_cart. On success, empties the real platform cart first
   *  (it may hold stale contents from before this session existed). */
  async create(): Promise<CreateResult> {
    if (this.state === "active") {
      return {
        ok: false,
        error: "A cart already exists (id: " + this.cartId + "). Call get_cart to read it, or cancel_cart to discard it before creating a new one.",
      };
    }
    await this.primitives.emptyCart();
    this.cartId = this.mintCartId();
    this.state = "active";
    this.cachedContinueUrl = null;
    this.continueUrlDirty = true;
    return { ok: true, id: this.cartId, cart: { lines: [] } };
  }

  async get(id: string): Promise<GetResult> {
    if (!this.matches(id)) return { ok: false, notFound: true };
    const cart = await this.primitives.getCartRaw();
    return { ok: true, id, cart };
  }

  /** The diff-and-reconcile shim. Matches submitted line items to existing
   *  ones by id when present (a submitted id that doesn't match any current
   *  line is an ERROR, not a silent add); id-less submitted items are new
   *  additions; any current line omitted from the submitted array is
   *  removed. Issues ZERO platform calls when the submitted state exactly
   *  matches the current state. */
  async update(id: string, desired: DesiredLine[]): Promise<UpdateResult> {
    if (!this.matches(id)) return { ok: false, notFound: true };

    const current = await this.primitives.getCartRaw();
    const currentById = new Map(current.lines.map((l) => [l.id, l]));
    const toAdd: DesiredLine[] = [];
    const toUpdate: Array<{ id: string; quantity: number }> = [];
    const seen = new Set<string>();

    for (const d of desired) {
      if (d.id) {
        const existing = currentById.get(d.id);
        if (!existing) return { ok: false, invalidLineId: d.id };
        seen.add(d.id);
        if (existing.quantity !== d.quantity) toUpdate.push({ id: d.id, quantity: d.quantity });
      } else {
        toAdd.push(d);
      }
    }
    const toRemove = current.lines.filter((l) => !seen.has(l.id)).map((l) => l.id);

    if (toAdd.length === 0 && toUpdate.length === 0 && toRemove.length === 0) {
      return { ok: true, cart: current }; // nothing changed — zero platform calls
    }

    for (const lineId of toRemove) await this.primitives.removeItem(lineId);
    for (const u of toUpdate) await this.primitives.setItemQty(u.id, u.quantity);
    for (const a of toAdd) await this.primitives.addItem(a.productId, a.quantity);

    this.continueUrlDirty = true;
    const updated = await this.primitives.getCartRaw();
    return { ok: true, cart: updated };
  }

  /** Empties the REAL platform cart (no orphaned state) and marks the
   *  session canceled. Returns the cart's state from just BEFORE emptying —
   *  UCP's own spec: "Business MUST return the cart state before deletion." */
  async cancel(id: string): Promise<CancelResult> {
    if (!this.matches(id)) return { ok: false, notFound: true };
    const snapshot = await this.primitives.getCartRaw();
    await this.primitives.emptyCart();
    this.state = "canceled";
    this.cachedContinueUrl = null;
    this.continueUrlDirty = true;
    return { ok: true, cart: snapshot };
  }

  /** Lazy, cached, invalidated only on an actual line-item change — never
   *  minted for an empty cart. See this file's header comment for why. */
  async resolveContinueUrl(cart: NormalizedCart): Promise<string | undefined> {
    if (cart.lines.length === 0) return undefined;
    if (!this.continueUrlDirty && this.cachedContinueUrl) return this.cachedContinueUrl;
    const url = await this.primitives.checkoutUrl();
    this.cachedContinueUrl = url;
    this.continueUrlDirty = false;
    return url;
  }
}

// ---------------------------------------------------------------------------
// Tool registration — the canonical UCP catalog + cart surface, and nothing
// else. Call once from server.ts with this platform's primitives.
// ---------------------------------------------------------------------------

// Tool annotations (readOnlyHint/destructiveHint/idempotentHint/openWorldHint)
// below are HINTS, not a security boundary. Per the MCP SDK's own doc
// comment on ToolAnnotations: "all properties in ToolAnnotations are
// **hints**. They are not guaranteed to provide a faithful description of
// tool behavior (including descriptive properties like 'title'). Clients
// should never make tool use decisions based on ToolAnnotations received
// from untrusted servers." They supplement this server's own code
// discipline (the payment boundary described above) — they never replace it.

export function registerUcpTools(server: McpServer, primitives: { catalog: CatalogPrimitives; cart: CartPrimitives }): void {
  const session = new CartSession(primitives.cart);

  server.registerTool(
    "search_catalog",
    {
      title: "Search catalog",
      description: "Search this store's product catalog by keyword.",
      inputSchema: {
        meta: metaSchema,
        catalog: z.object({
          query: z.string(),
          context: z.record(z.string(), z.unknown()).optional(),
          filters: z.record(z.string(), z.unknown()).optional(),
          pagination: z.object({ limit: z.number().int().min(1).max(50).optional() }).optional(),
        }),
      },
      annotations: { readOnlyHint: true, destructiveHint: false, openWorldHint: true },
    },
    async ({ catalog }) => {
      const limit = catalog.pagination?.limit ?? 10;
      const products = await primitives.catalog.searchProducts(catalog.query, limit);
      return toolResult({ products, pagination: { has_next_page: false } });
    },
  );

  server.registerTool(
    "lookup_catalog",
    {
      title: "Lookup catalog",
      description:
        "Look up one or more products by identifier. Unknown identifiers are reported in messages, not errors — a partial result is a normal outcome.",
      inputSchema: {
        meta: metaSchema,
        catalog: z.object({ ids: z.array(z.string()).min(1), context: z.record(z.string(), z.unknown()).optional() }),
      },
      annotations: { readOnlyHint: true, destructiveHint: false, openWorldHint: true },
    },
    async ({ catalog }) => {
      const products: NormalizedProduct[] = [];
      const messages: Array<{ type: string; code: string; content: string }> = [];
      for (const id of catalog.ids) {
        try {
          products.push(await primitives.catalog.getProduct(id));
        } catch {
          messages.push({ type: "info", code: "not_found", content: id });
        }
      }
      return toolResult({ products, ...(messages.length ? { messages } : {}) });
    },
  );

  server.registerTool(
    "get_product",
    {
      title: "Get product",
      description: "Get full detail for one product by identifier.",
      inputSchema: {
        meta: metaSchema,
        catalog: z.object({
          id: z.string(),
          selected: z.array(z.unknown()).optional(),
          preferences: z.array(z.string()).optional(),
          context: z.record(z.string(), z.unknown()).optional(),
        }),
      },
      annotations: { readOnlyHint: true, destructiveHint: false, openWorldHint: true },
    },
    async ({ catalog }) => {
      try {
        const product = await primitives.catalog.getProduct(catalog.id);
        return toolResult({ product });
      } catch {
        return errorResult("not_found", "Product not found: " + catalog.id);
      }
    },
  );

  server.registerTool(
    "create_cart",
    {
      title: "Create cart",
      description:
        "Create a new cart session. Always starts EMPTY — this server does not apply initial line_items from the request; call update_cart immediately after to populate it. Errors if a cart is already active (call get_cart to read it, or cancel_cart to discard it, first).",
      inputSchema: { meta: metaSchema, cart: cartPayloadSchema },
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: false, openWorldHint: true },
    },
    async () => {
      const result = await session.create();
      if (!result.ok) return errorResult("cart_already_exists", result.error);
      return toolResult({ id: result.id, line_items: [] });
    },
  );

  server.registerTool(
    "get_cart",
    {
      title: "Get cart",
      description: "Get a cart session by id. Returns not_found if the cart doesn't exist, has expired, or was canceled.",
      inputSchema: { meta: metaSchema, id: z.string() },
      annotations: { readOnlyHint: true, destructiveHint: false, openWorldHint: true },
    },
    async ({ id }) => {
      const result = await session.get(id);
      if (!result.ok) return notFoundResult();
      const continue_url = await session.resolveContinueUrl(result.cart);
      return toolResult({
        id: result.id,
        line_items: toUcpLineItems(result.cart.lines),
        ...(result.cart.currency ? { currency: result.cart.currency } : {}),
        ...(continue_url ? { continue_url } : {}),
      });
    },
  );

  server.registerTool(
    "update_cart",
    {
      title: "Update cart",
      description:
        "Replace the cart's full contents. Submit ALL desired line items — omitting an existing line item removes it. A submitted line item's id must reference an existing line (errors otherwise); a line item with no id is treated as a new addition. Quantity must be at least 1 — there is no quantity-0 removal signal.",
      inputSchema: { meta: metaSchema, id: z.string(), cart: cartPayloadSchema },
      annotations: { readOnlyHint: false, destructiveHint: false, idempotentHint: true, openWorldHint: true },
    },
    async ({ id, cart }) => {
      const desired: DesiredLine[] = cart.line_items.map((li) => ({ id: li.id, productId: li.item.id, quantity: li.quantity }));
      const result = await session.update(id, desired);
      if (!result.ok) {
        if ("notFound" in result) return notFoundResult();
        return errorResult("not_found", "Line item '" + result.invalidLineId + "' not found in the current cart.");
      }
      const continue_url = await session.resolveContinueUrl(result.cart);
      return toolResult({
        id,
        line_items: toUcpLineItems(result.cart.lines),
        ...(result.cart.currency ? { currency: result.cart.currency } : {}),
        ...(continue_url ? { continue_url } : {}),
      });
    },
  );

  server.registerTool(
    "cancel_cart",
    {
      title: "Cancel cart",
      description:
        "Cancel the cart session — empties it for real on the store and marks it gone. Subsequent operations on this cart id return not_found; call create_cart to start a new one.",
      inputSchema: { meta: metaSchema, id: z.string() },
      annotations: { readOnlyHint: false, destructiveHint: true, idempotentHint: true, openWorldHint: true },
    },
    async ({ id }) => {
      const result = await session.cancel(id);
      if (!result.ok) return notFoundResult();
      return toolResult({
        id,
        line_items: toUcpLineItems(result.cart.lines),
        ...(result.cart.currency ? { currency: result.cart.currency } : {}),
      });
    },
  );
}

src/server.ts:
/**
 * Adeptra Merchant — Wix MCP Shopping Server.
 *
 * Implements UCP's canonical catalog + cart tool surface (search_catalog,
 * lookup_catalog, get_product, create_cart, get_cart, update_cart,
 * cancel_cart — see mcpTools.ts) against Wix's eCommerce API. HARD
 * BOUNDARY: this server never processes payment. The cart's continue_url
 * hands off to Wix's own hosted checkout page. See wix.ts's header comment
 * for the explicit list of endpoints this server deliberately never calls,
 * and README.md's "About UCP protocol conformance" section for exactly
 * what is and isn't UCP-conformant here.
 */

import "./loadEnv.js"; // MUST be the first import — see loadEnv.ts's header

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { registerUcpTools } from "./mcpTools.js";
import { assertCatalogV3, searchProducts, getProduct, getCartRaw, addItem, setItemQty, removeItem, emptyCart, checkoutUrl } from "./wix.js";

if (!process.env.WIX_CLIENT_ID || !process.env.WIX_SITE_URL) {
  console.error("Set WIX_CLIENT_ID and WIX_SITE_URL in .env (see .env.example) before starting this server.");
  process.exit(1);
}

const server = new McpServer({ name: "wix-shopping-server", version: "1.0.0" });

registerUcpTools(server, {
  catalog: { searchProducts, getProduct },
  cart: { getCartRaw, addItem, setItemQty, removeItem, emptyCart, checkoutUrl },
});

async function main() {
  await assertCatalogV3(); // hard-fails with a clear message if this site isn't on Catalog V3 — see wix.ts
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("Wix MCP shopping server running (stdio).");
}

main().catch((e) => {
  console.error(`Failed to start: ${(e as Error).message ?? e}`);
  // process.exitCode, not process.exit() — calling exit() immediately after
  // an in-flight fetch (assertCatalogV3, above) can crash Node on some
  // platforms; setting the code and letting the event loop drain naturally
  // avoids that while still exiting non-zero.
  process.exitCode = 1;
});

src/wix.ts:
/**
 * Thin Wix eCommerce REST client. Catalog reads + cart building + a
 * payment-free checkout-URL mint ONLY. Exports the primitive functions
 * registerUcpTools (see mcpTools.ts) wires up as this platform's
 * CatalogPrimitives/CartPrimitives — every function here returns
 * NORMALIZED shapes (NormalizedProduct / NormalizedCart), not Wix's own raw
 * REST response shape.
 *
 * ENDPOINTS THIS FILE DELIBERATELY NEVER CALLS, AND WHY:
 *   - POST /ecom/v1/orders (Create Order) — creates a real order. Never called.
 *   - Anything that submits or authorizes payment details. Never called, and
 *     never imported/referenced — this file has no payment-related code path
 *     at all. Payment happens exclusively on Wix's own hosted checkout page
 *     (the URL checkoutUrl() returns), entered directly by the shopper.
 *   - Any /stores/v3/products WRITE endpoint (create/update/delete products).
 *     Catalog access here is read-only (search + get by id).
 *   - Any orders/customers/analytics/settings read endpoint. This client
 *     reads catalog and the CURRENT VISITOR'S OWN cart only.
 *
 * SCOPE REALITY (see README.md's "About the permissions you're granting"):
 * Wix's narrowest documented scopes for what this server needs are broader
 * than what it actually uses — SCOPE.DC-ECOM-MEGA.MANAGE-ECOM ("Manage
 * eCommerce - all permissions") for cart writes, and
 * SCOPE.DC-STORES.MANAGE-ORDERS ("Manage Orders" — also covers reading
 * orders and creating fulfillments) for checkout creation. There is no
 * narrower option Wix exposes today. This file's own code is the actual
 * boundary: everything above this comment block is the complete list of
 * endpoints it will ever call.
 *
 * AUTH: a visitor access token (Client ID only, no client secret — Wix's
 * public-client flow for anonymous/headless sessions) doubles as the cart's
 * session identity, the same role WooCommerce's Cart-Token header plays —
 * every /ecom/v1/carts/current/* call made with the same token operates on
 * the same visitor's cart, no separate cart id needed on Wix's own side
 * (mcpTools.ts's session state machine layers UCP's own cart id concept on
 * top of this single implicit cart). One token per running process,
 * matching the same "one process = one shopper session" assumption the
 * WooCommerce scaffold makes. NOTE: the token endpoint (POST /oauth2/token)
 * is currently marked "Developer Preview" in Wix's own docs as of when this
 * was generated — it may change. Tokens last 4 hours; this client does not
 * implement refresh-token renewal for v1 simplicity — a session longer than
 * that gets a fresh anonymous visitor identity (and empty cart) on its next
 * call, which is very unlikely to matter for a typical MCP session lifetime.
 *
 * CATALOG VERSION: this client targets Wix Catalog V3 only. Wix Stores sites
 * run ONE catalog version (V1 or V3, not backward-compatible), and existing
 * stores may still be on V1. assertCatalogV3() is called on startup by
 * server.ts and exits with a clear message rather than letting a V1 site
 * fail confusingly deep inside a catalog call.
 */

import type { NormalizedProduct, NormalizedCart } from "./mcpTools.js";

// Read here, but NOT enforced at module load — server.ts's own top-level
// check (before it imports anything that calls these) is what produces the
// clean "set your env vars" message. A throw here at import time would win
// the race against that check every time (imports evaluate before the
// importing module's own body runs) and surface as an ugly uncaught
// exception instead. The check below, inside getAccessToken(), is
// defense-in-depth for anyone importing this file directly.
const CLIENT_ID = process.env.WIX_CLIENT_ID;
const SITE_URL = process.env.WIX_SITE_URL;

const API_BASE = "https://www.wixapis.com";
const STORES_APP_ID = "215238eb-22a5-4c36-9e7b-e7c08025e04e"; // fixed, universal Wix Stores app id — not merchant-specific, safe to hardcode

let accessToken: string | null = null;

async function getAccessToken(): Promise<string> {
  if (accessToken) return accessToken;
  if (!CLIENT_ID || !SITE_URL) {
    throw new Error("Set WIX_CLIENT_ID and WIX_SITE_URL in .env (see .env.example).");
  }
  const res = await fetch(`${API_BASE}/oauth2/token`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ clientId: CLIENT_ID, grantType: "anonymous" }),
  });
  const text = await res.text();
  if (!res.ok) throw new Error(`Wix OAuth token request -> ${res.status}: ${text}`);
  const data = JSON.parse(text) as { access_token: string };
  accessToken = data.access_token;
  return accessToken;
}

async function wixFetch(path: string, init: RequestInit = {}): Promise<any> {
  const token = await getAccessToken();
  const headers: Record<string, string> = {
    "content-type": "application/json",
    authorization: `Bearer ${token}`,
    ...(init.headers as Record<string, string> | undefined),
  };
  const res = await fetch(`${API_BASE}${path}`, { ...init, headers });
  const text = await res.text();
  if (!res.ok) {
    throw new Error(`Wix API ${init.method ?? "GET"} ${path} -> ${res.status}: ${text}`);
  }
  return text ? JSON.parse(text) : null;
}

/** Throws a clear, actionable error if this site isn't on Catalog V3 — called
 *  once at server startup, before any tool is registered, so the process
 *  fails loudly instead of hitting confusing runtime errors later. A single,
 *  cheap, parameterless call (per Wix's own docs: catalog version is
 *  permanent for a site, one call is sufficient for the whole process).
 *  Throws rather than calling process.exit() itself — exiting immediately
 *  after an in-flight fetch can crash Node on some platforms; main()'s own
 *  catch handler is the one place that sets the exit code, once nothing is
 *  still in flight. */
export async function assertCatalogV3(): Promise<void> {
  const result = await wixFetch("/stores/v3/provision/version");
  const version = result?.catalogVersion;
  if (version === "V3_CATALOG") return;
  if (version === "STORES_NOT_INSTALLED") {
    throw new Error("Wix Stores does not appear to be installed on this site. Install/enable Wix Stores, then retry.");
  }
  throw new Error(
    `This server requires Wix Catalog V3; your site is on ${version === "V1_CATALOG" ? "Catalog V1" : `an unrecognized catalog version (${String(version)})`}. See README.md's "Known gotcha: Catalog V1 vs V3" for what this means and how to check.`,
  );
}

interface RawProduct {
  id: string;
  name: string;
  plainDescription?: string;
}

function toNormalizedProduct(p: RawProduct): NormalizedProduct {
  return { id: p.id, title: p.name };
}

export async function searchProducts(query: string, limit: number): Promise<NormalizedProduct[]> {
  const result = await wixFetch("/stores/v3/products/search", {
    method: "POST",
    body: JSON.stringify({
      search: { expression: query, fields: ["name"], fuzzy: true },
      fields: ["DESCRIPTION"],
      cursorPaging: { limit },
    }),
  });
  const products: RawProduct[] = result?.products ?? [];
  return products.map(toNormalizedProduct);
}

export async function getProduct(id: string): Promise<NormalizedProduct> {
  const result = await wixFetch(`/stores/v3/products/${id}`);
  return toNormalizedProduct(result?.product);
}

/** Wix requires a variantId for every cart line, even for a product with no
 *  real options (it gets one "default variant"). This client always uses
 *  the FIRST variant returned by a fresh product lookup — a real
 *  simplification (a product with genuine size/color options would need
 *  variant selection this scaffold doesn't expose) disclosed in README.md,
 *  not hidden. A future version could accept a variant id from the caller
 *  instead of always picking the first one. */
async function firstVariantId(productId: string): Promise<string> {
  const result = await wixFetch(`/stores/v3/products/${productId}`);
  const variantId = result?.product?.variantsInfo?.variants?.[0]?.variant?.id ?? result?.product?.variantsInfo?.variants?.[0]?.id;
  if (!variantId) throw new Error(`Wix product ${productId} has no variants — cannot add to cart.`);
  return variantId;
}

interface RawCartLineItem {
  id: string;
  quantity: number;
  catalogReference?: { catalogItemId: string };
  productName?: { original?: string };
  price?: { amount?: string };
}

interface RawCart {
  lineItems?: RawCartLineItem[];
  currency?: string;
}

function toNormalizedCart(raw: RawCart | undefined): NormalizedCart {
  const lines = (raw?.lineItems ?? []).map((li) => ({
    id: li.id,
    productId: li.catalogReference?.catalogItemId ?? "",
    quantity: li.quantity,
    title: li.productName?.original,
    price: li.price?.amount,
  }));
  return { lines, currency: raw?.currency };
}

export async function getCartRaw(): Promise<NormalizedCart> {
  const result = await wixFetch("/ecom/v1/carts/current");
  return toNormalizedCart(result?.cart);
}

export async function addItem(productId: string, quantity: number): Promise<void> {
  const variantId = await firstVariantId(productId);
  await wixFetch("/ecom/v1/carts/current/add-to-cart", {
    method: "POST",
    body: JSON.stringify({
      lineItems: [
        {
          catalogReference: { appId: STORES_APP_ID, catalogItemId: productId, options: { variantId } },
          quantity,
        },
      ],
    }),
  });
}

export async function setItemQty(lineItemId: string, quantity: number): Promise<void> {
  await wixFetch("/ecom/v1/carts/current/update-line-items-quantity", {
    method: "POST",
    body: JSON.stringify({ lineItems: [{ id: lineItemId, quantity }] }),
  });
}

export async function removeItem(lineItemId: string): Promise<void> {
  await wixFetch("/ecom/v1/carts/current/remove-line-items", {
    method: "POST",
    body: JSON.stringify({ lineItemIds: [lineItemId] }),
  });
}

/** Wix's remove-line-items endpoint already accepts multiple ids in one
 *  call (verified — the same endpoint removeItem() uses above, just with
 *  every current line id instead of one), so emptying the cart is a single
 *  request, not a loop. */
export async function emptyCart(): Promise<void> {
  const cart = await getCartRaw();
  if (cart.lines.length === 0) return;
  await wixFetch("/ecom/v1/carts/current/remove-line-items", {
    method: "POST",
    body: JSON.stringify({ lineItemIds: cart.lines.map((l) => l.id) }),
  });
}

/** Two Wix API calls, not one: create a checkout object from the current
 *  cart (returns only a checkoutId, no URL), then create a redirect session
 *  for that checkout (returns the actual URL). Neither call authorizes or
 *  completes payment — createCheckoutFromCurrentCart creates a pre-payment
 *  checkout object, and the redirect session's URL points to Wix's own
 *  hosted checkout page where the SHOPPER enters payment directly with Wix.
 *  NOT cheap or free of side effects — see this file's header comment and
 *  mcpTools.ts's continue_url caching, which is what keeps this from being
 *  called on every single cart read. */
export async function checkoutUrl(): Promise<string> {
  const checkoutResult = await wixFetch("/ecom/v1/carts/current/create-checkout", {
    method: "POST",
    body: JSON.stringify({ channelType: "WEB" }),
  });
  const checkoutId = checkoutResult?.checkoutId;
  if (!checkoutId) throw new Error("Wix did not return a checkoutId from create-checkout.");

  const redirectResult = await wixFetch("/redirect-session/v1/redirect-session", {
    method: "POST",
    body: JSON.stringify({
      ecomCheckout: { checkoutId },
      callbacks: { postFlowUrl: SITE_URL },
    }),
  });
  const fullUrl = redirectResult?.redirectSession?.fullUrl;
  if (!fullUrl) throw new Error("Wix did not return a redirect URL from create-redirect-session.");
  return fullUrl;
}
